  1→import React, { useState } from 'react';
  2→import { User, ContentWriterInput, GeneratedContent, ContentVertical, ContentType } from '../types';
  3→import { generateContent } from '../services/content_writer';
  4→import { useTranslation } from '../i18n';
  5→import { ArrowLeft, Feather, Copy, Download, Check, Loader2, RefreshCw, ShoppingBag, Cloud, Building, UtensilsCrossed, Heart, DollarSign, Scale, GraduationCap, Globe, FileText, Layout, Mail, Tag, Share2, Newspaper, BookOpen, Send, Sparkles } from 'lucide-react';
  6→
  7→interface Props {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onDeductCredits: (amount: number) => boolean;
 11→}
 12→
 13→const VERTICAL_ICONS: { id: ContentVertical; icon: React.ElementType; color: string }[] = [
 14→  { id: 'ecommerce', icon: ShoppingBag, color: 'text-pink-400' },
 15→  { id: 'saas', icon: Cloud, color: 'text-blue-400' },
 16→  { id: 'immobilier', icon: Building, color: 'text-purple-400' },
 17→  { id: 'restauration', icon: UtensilsCrossed, color: 'text-orange-400' },
 18→  { id: 'sante', icon: Heart, color: 'text-red-400' },
 19→  { id: 'finance', icon: DollarSign, color: 'text-purple-300' },
 20→  { id: 'juridique', icon: Scale, color: 'text-purple-400' },
 21→  { id: 'education', icon: GraduationCap, color: 'text-cyan-400' },
 22→  { id: 'general', icon: Globe, color: 'text-gray-400' },
 23→];
 24→
 25→const CONTENT_TYPE_ICONS: { id: ContentType; icon: React.ElementType; cost: number }[] = [
 26→  { id: 'product_description', icon: FileText, cost: 2 },
 27→  { id: 'landing_page', icon: Layout, cost: 3 },
 28→  { id: 'sales_email', icon: Mail, cost: 2 },
 29→  { id: 'meta_tags', icon: Tag, cost: 1 },
 30→  { id: 'social_post', icon: Share2, cost: 1 },
 31→  { id: 'press_release', icon: Newspaper, cost: 2 },
 32→  { id: 'case_study', icon: BookOpen, cost: 3 },
 33→  { id: 'newsletter', icon: Send, cost: 2 },
 34→];
 35→
 36→const ContentWriter: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
 37→  const { t, locale } = useTranslation();
 38→  const [step, setStep] = useState<'vertical' | 'type' | 'form' | 'result'>('vertical');
 39→  const [selectedVertical, setSelectedVertical] = useState<ContentVertical>('general');
 40→  const [selectedType, setSelectedType] = useState<ContentType>('product_description');
 41→  const [isGenerating, setIsGenerating] = useState(false);
 42→  const [result, setResult] = useState<GeneratedContent | null>(null);
 43→  const [copied, setCopied] = useState(false);
 44→
 45→  // Form
 46→  const [brandName, setBrandName] = useState('');
 47→  const [brandUrl, setBrandUrl] = useState('');
 48→  const [productOrService, setProductOrService] = useState('');
 49→  const [targetAudience, setTargetAudience] = useState('');
 50→  const [tone, setTone] = useState<ContentWriterInput['tone']>('professionnel');
 51→  const [language, setLanguage] = useState<'fr' | 'en' | 'es'>(locale as 'fr' | 'en' | 'es');
 52→  const [additionalContext, setAdditionalContext] = useState('');
 53→
 54→  const currentTypeCost = CONTENT_TYPE_ICONS.find(ct => ct.id === selectedType)?.cost || 2;
 55→
 56→  // Get translated labels
 57→  const getVerticalLabel = (id: ContentVertical) => t.contentWriter.verticals[id] || id;
 58→  const getContentTypeLabel = (id: ContentType) => t.contentWriter.contentTypes[id] || id;
 59→  const getToneLabel = (id: string) => t.contentWriter.tones[id] || id;
 60→
 61→  const handleGenerate = async () => {
 62→    if (!brandName || !productOrService || !targetAudience) {
 63→      alert(locale === 'en' ? 'Please fill in all required fields.' : locale === 'es' ? 'Por favor, rellena todos los campos obligatorios.' : 'Veuillez remplir tous les champs obligatoires.');
 64→      return;
 65→    }
 66→
 67→    const canProceed = onDeductCredits(currentTypeCost);
 68→    if (!canProceed) return;
 69→
 70→    setIsGenerating(true);
 71→    try {
 72→      const output = await generateContent({
 73→        vertical: selectedVertical,
 74→        contentType: selectedType,
 75→        brandName,
 76→        brandUrl: brandUrl || undefined,
 77→        productOrService,
 78→        targetAudience,
 79→        tone,
 80→        language,
 81→        additionalContext: additionalContext || undefined,
 82→      });
 83→      setResult(output);
 84→      setStep('result');
 85→    } catch (error) {
 86→      console.error(error);
 87→      alert(locale === 'en' ? 'Generation error.' : locale === 'es' ? 'Error de generacion.' : 'Erreur lors de la generation.');
 88→    } finally {
 89→      setIsGenerating(false);
 90→    }
 91→  };
 92→
 93→  const handleCopy = (text: string) => {
 94→    navigator.clipboard.writeText(text);
 95→    setCopied(true);
 96→    setTimeout(() => setCopied(false), 2000);
 97→  };
 98→
 99→  const handleDownload = (filename: string, content: string) => {
100→    const blob = new Blob([content], { type: 'text/markdown' });
101→    const url = URL.createObjectURL(blob);
102→    const a = document.createElement('a');
103→    a.href = url;
104→    a.download = filename;
105→    document.body.appendChild(a);
106→    a.click();
107→    document.body.removeChild(a);
108→    URL.revokeObjectURL(url);
109→  };
110→
111→  const handleRegenerate = () => {
112→    setResult(null);
113→    setStep('form');
114→  };
115→
116→  const ScoreRingMini = ({ score }: { score: number }) => {
117→    const color = score >= 75 ? '#a855f7' : score >= 50 ? '#c084fc' : '#ef4444';
118→    const circumference = 2 * Math.PI * 28;
119→    const offset = circumference - (score / 100) * circumference;
120→    return (
121→      <div className="relative w-20 h-20">
122→        <svg className="w-20 h-20 -rotate-90" viewBox="0 0 64 64">
123→          <circle cx="32" cy="32" r="28" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="4" />
124→          <circle cx="32" cy="32" r="28" fill="none" stroke={color} strokeWidth="4" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
125→        </svg>
126→        <div className="absolute inset-0 flex items-center justify-center">
127→          <span className="text-lg font-bold text-white">{score}</span>
128→        </div>
129→      </div>
130→    );
131→  };
132→
133→  return (
134→    <div className="max-w-5xl mx-auto px-4 py-10 animate-in fade-in duration-500 min-h-screen">
135→      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
136→        <ArrowLeft size={18} className="mr-2" /> {t.common.back}
137→      </button>
138→
139→      {/* Header */}
140→      <div className="flex items-center gap-4 mb-10">
141→        <div className="p-3 bg-rose-500/10 rounded-2xl">
142→          <Feather size={32} className="text-rose-400" />
143→        </div>
144→        <div>
145→          <h1 className="text-3xl font-bold text-white">{t.contentWriter.title}</h1>
146→          <p className="text-gray-400">{t.contentWriter.subtitle}</p>
147→        </div>
148→        <span className="ml-auto bg-rose-500/10 text-rose-400 text-xs font-bold px-3 py-1 rounded-full border border-rose-500/20 flex items-center gap-1">
149→          <Sparkles size={12} /> {t.contentWriter.framework}
150→        </span>
151→      </div>
152→
153→      {/* Step 1: Select Vertical */}
154→      {step === 'vertical' && (
155→        <div>
156→          <h2 className="text-xl font-bold text-white mb-6">1. {t.contentWriter.step1Title}</h2>
157→          <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
158→            {VERTICAL_ICONS.map(v => (
159→              <button
160→                key={v.id}
161→                onClick={() => { setSelectedVertical(v.id); setStep('type'); }}
162→                className="bg-[#0c0815] border border-purple-500/10 rounded-xl p-6 flex flex-col items-center gap-3 hover:bg-purple-500/10 hover:border-rose-500/30 transition-all group"
163→              >
164→                <v.icon size={32} className={`${v.color} group-hover:scale-110 transition-transform`} />
165→                <span className="text-sm font-bold text-gray-300 group-hover:text-white">{getVerticalLabel(v.id)}</span>
166→              </button>
167→            ))}
168→          </div>
169→        </div>
170→      )}
171→
172→      {/* Step 2: Select Content Type */}
173→      {step === 'type' && (
174→        <div>
175→          <div className="flex items-center gap-2 mb-2">
176→            <button onClick={() => setStep('vertical')} className="text-gray-500 hover:text-white text-sm">&larr; Vertical</button>
177→            <span className="text-gray-600 text-sm">/</span>
178→            <span className="text-rose-400 text-sm font-medium">{getVerticalLabel(selectedVertical)}</span>
179→          </div>
180→          <h2 className="text-xl font-bold text-white mb-6">2. {t.contentWriter.step2Title}</h2>
181→          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
182→            {CONTENT_TYPE_ICONS.map(ct => (
183→              <button
184→                key={ct.id}
185→                onClick={() => { setSelectedType(ct.id); setStep('form'); }}
186→                className="bg-[#0c0815] border border-purple-500/10 rounded-xl p-5 flex flex-col items-center gap-3 hover:bg-purple-500/10 hover:border-rose-500/30 transition-all group"
187→              >
188→                <ct.icon size={28} className="text-rose-400 group-hover:scale-110 transition-transform" />
189→                <span className="text-xs font-bold text-gray-300 group-hover:text-white text-center">{getContentTypeLabel(ct.id)}</span>
190→                <span className="text-[10px] text-gray-500">{ct.cost} {t.common.credits}</span>
191→              </button>
192→            ))}
193→          </div>
194→        </div>
195→      )}
196→
197→      {/* Step 3: Form */}
198→      {step === 'form' && (
199→        <div>
200→          <div className="flex items-center gap-2 mb-2">
201→            <button onClick={() => setStep('type')} className="text-gray-500 hover:text-white text-sm">&larr; Type</button>
202→            <span className="text-gray-600 text-sm">/</span>
203→            <span className="text-rose-400 text-sm font-medium">{getContentTypeLabel(selectedType)}</span>
204→          </div>
205→          <h2 className="text-xl font-bold text-white mb-6">3. {t.contentWriter.step3Title}</h2>
206→          <div className="bg-[#0c0815] border border-purple-500/10 rounded-2xl p-6 space-y-5">
207→            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
208→              <div>
209→                <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.brandName} *</label>
210→                <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
211→              </div>
212→              <div>
213→                <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.brandUrl} ({t.common.optional})</label>
214→                <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
215→              </div>
216→            </div>
217→            <div>
218→              <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.productOrService} *</label>
219→              <input value={productOrService} onChange={e => setProductOrService(e.target.value)} placeholder="Ex: AEO optimization platform" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
220→            </div>
221→            <div>
222→              <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.targetAudience} *</label>
223→              <input value={targetAudience} onChange={e => setTargetAudience(e.target.value)} placeholder="Ex: B2B Marketing Directors" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
224→            </div>
225→            <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
226→              <div>
227→                <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.tone}</label>
228→                <select value={tone} onChange={e => setTone(e.target.value as any)} className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm">
229→                  {['professionnel', 'decontracte', 'autoritaire', 'empathique', 'technique'].map(toneId => (
230→                    <option key={toneId} value={toneId}>{getToneLabel(toneId)}</option>
231→                  ))}
232→                </select>
233→              </div>
234→              <div>
235→                <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.language}</label>
236→                <select value={language} onChange={e => setLanguage(e.target.value as 'fr' | 'en' | 'es')} className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm">
237→                  <option value="fr">{t.contentWriter.contentLanguages.fr}</option>
238→                  <option value="en">{t.contentWriter.contentLanguages.en}</option>
239→                  <option value="es">{t.contentWriter.contentLanguages.es}</option>
240→                </select>
241→              </div>
242→              <div className="flex items-end">
243→                <div className="bg-rose-500/10 border border-rose-500/20 rounded-lg px-4 py-3 text-center w-full">
244→                  <span className="text-xs text-gray-400">{t.common.score}</span>
245→                  <span className="block text-lg font-bold text-rose-400">{currentTypeCost} GTO</span>
246→                </div>
247→              </div>
248→            </div>
249→            <div>
250→              <label className="block text-sm text-gray-400 mb-1.5">{t.contentWriter.additionalContext} ({t.common.optional})</label>
251→              <textarea value={additionalContext} onChange={e => setAdditionalContext(e.target.value)} rows={3} placeholder="..." className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm resize-none" />
252→            </div>
253→            <button
254→              onClick={handleGenerate}
255→              disabled={isGenerating || !brandName || !productOrService || !targetAudience}
256→              className="w-full bg-rose-500 text-white font-bold py-3.5 rounded-xl hover:bg-rose-600 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
257→            >
258→              {isGenerating ? <><Loader2 size={18} className="animate-spin" /> {t.common.loading}</> : <><Feather size={18} /> {t.contentWriter.generateContent}</>}
259→            </button>
260→          </div>
261→        </div>
262→      )}
263→
264→      {/* Step 4: Result */}
265→      {step === 'result' && result && (
266→        <div>
267→          <div className="flex items-center gap-2 mb-6">
268→            <button onClick={handleRegenerate} className="text-gray-500 hover:text-white text-sm">&larr; {t.contentWriter.modifyBrief}</button>
269→          </div>
270→
271→          {/* Score + Meta */}
272→          <div className="flex items-center gap-6 mb-8 bg-[#0c0815] border border-purple-500/10 rounded-2xl p-6">
273→            <ScoreRingMini score={result.aeoScore} />
274→            <div className="flex-1">
275→              <h3 className="text-lg font-bold text-white">{result.title}</h3>
276→              {result.metaDescription && <p className="text-sm text-gray-400 mt-1">{result.metaDescription}</p>}
277→            </div>
278→            <div className="flex gap-2">
279→              <button onClick={() => handleCopy(result.content)} className="p-2.5 bg-purple-500/5 rounded-lg hover:bg-purple-500/10 transition-colors" title={t.common.copy}>
280→                {copied ? <Check size={16} className="text-purple-300" /> : <Copy size={16} className="text-gray-400" />}
281→              </button>
282→              <button onClick={() => handleDownload(`${brandName}-${selectedType}.md`, result.content)} className="p-2.5 bg-purple-500/5 rounded-lg hover:bg-purple-500/10 transition-colors" title={t.common.download}>
283→                <Download size={16} className="text-gray-400" />
284→              </button>
285→              <button onClick={handleRegenerate} className="p-2.5 bg-purple-500/5 rounded-lg hover:bg-purple-500/10 transition-colors" title={t.common.regenerate}>
286→                <RefreshCw size={16} className="text-gray-400" />
287→              </button>
288→            </div>
289→          </div>
290→
291→          {/* AEO Tips */}
292→          {result.aeoTips.length > 0 && (
293→            <div className="mb-6 bg-rose-500/5 border border-rose-500/10 rounded-xl p-5">
294→              <h4 className="text-sm font-bold text-rose-400 mb-3">{t.contentWriter.aeoTips}</h4>
295→              <ul className="space-y-1.5">
296→                {result.aeoTips.map((tip, i) => (
297→                  <li key={i} className="text-sm text-gray-300 flex items-start gap-2">
298→                    <span className="text-rose-400 mt-0.5">&#x2022;</span> {tip}
299→                  </li>
300→                ))}
301→              </ul>
302→            </div>
303→          )}
304→
305→          {/* Content */}
306→          <div className="bg-[#0c0815] border border-purple-500/10 rounded-2xl p-6">
307→            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 leading-relaxed">
308→              {result.content}
309→            </div>
310→          </div>
311→
312→          {/* Schema Markup */}
313→          {result.schemaMarkup && (
314→            <div className="mt-6 bg-[#0c0815] border border-purple-500/10 rounded-2xl p-6">
315→              <div className="flex items-center justify-between mb-3">
316→                <h4 className="text-sm font-bold text-gray-200">{t.contentWriter.schemaJsonLd}</h4>
317→                <button onClick={() => handleCopy(result.schemaMarkup || '')} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
318→                  <Copy size={12} /> {t.common.copy}
319→                </button>
320→              </div>
321→              <pre className="text-xs text-purple-300 bg-black/40 rounded-lg p-4 overflow-x-auto">{result.schemaMarkup}</pre>
322→            </div>
323→          )}
324→        </div>
325→      )}
326→    </div>
327→  );
328→};
329→
330→export default ContentWriter;
