  1→import React, { useState } from 'react';
  2→import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
  3→import { scanReputation, generateReputationResponse } from '../services/reputation_service';
  4→import { useTranslation } from '../i18n';
  5→import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
  6→
  7→interface Props {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onDeductCredits: (amount: number) => boolean;
 11→}
 12→
 13→const AI_LOGOS: Record<string, string> = {
 14→  ChatGPT: 'bg-purple-500/20 text-purple-300',
 15→  Perplexity: 'bg-blue-500/20 text-blue-400',
 16→  Claude: 'bg-orange-500/20 text-orange-400',
 17→  Gemini: 'bg-purple-500/20 text-purple-400',
 18→  Copilot: 'bg-cyan-500/20 text-cyan-400',
 19→};
 20→
 21→const SEVERITY_CONFIG = {
 22→  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
 23→  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-purple-500/20' },
 24→  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
 25→};
 26→
 27→const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
 28→  const { t, locale } = useTranslation();
 29→
 30→  const SENTIMENT_CONFIG = {
 31→    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-purple-500/20', label: t.reputation.positive },
 32→    neutral: { color: 'text-gray-400', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: t.reputation.neutral },
 33→    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: t.reputation.negative },
 34→  };
 35→
 36→  const [step, setStep] = useState<'form' | 'results'>('form');
 37→  const [isScanning, setIsScanning] = useState(false);
 38→  const [report, setReport] = useState<ReputationReport | null>(null);
 39→
 40→  // Form
 41→  const [brandName, setBrandName] = useState('');
 42→  const [brandUrl, setBrandUrl] = useState('');
 43→  const [industry, setIndustry] = useState('');
 44→  const [competitorInput, setCompetitorInput] = useState('');
 45→  const [competitors, setCompetitors] = useState<string[]>([]);
 46→  const [keywordInput, setKeywordInput] = useState('');
 47→  const [keywords, setKeywords] = useState<string[]>([]);
 48→
 49→  // Action plan
 50→  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
 51→  const [actionPlan, setActionPlan] = useState<string | null>(null);
 52→  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
 53→  const [copied, setCopied] = useState(false);
 54→
 55→  const addCompetitor = () => {
 56→    if (competitorInput.trim() && competitors.length < 5) {
 57→      setCompetitors([...competitors, competitorInput.trim()]);
 58→      setCompetitorInput('');
 59→    }
 60→  };
 61→
 62→  const addKeyword = () => {
 63→    if (keywordInput.trim() && keywords.length < 10) {
 64→      setKeywords([...keywords, keywordInput.trim()]);
 65→      setKeywordInput('');
 66→    }
 67→  };
 68→
 69→  const handleScan = async () => {
 70→    if (!brandName || !industry) {
 71→      alert(locale === 'en' ? 'Please fill in the brand name and industry.' : locale === 'es' ? 'Por favor, rellena el nombre de la marca y el sector.' : 'Veuillez remplir le nom de la marque et le secteur.');
 72→      return;
 73→    }
 74→
 75→    const canProceed = onDeductCredits(3);
 76→    if (!canProceed) return;
 77→
 78→    setIsScanning(true);
 79→    try {
 80→      const result = await scanReputation({
 81→        brandName,
 82→        brandUrl: brandUrl || undefined,
 83→        competitors: competitors.length > 0 ? competitors : undefined,
 84→        industry,
 85→        keywords: keywords.length > 0 ? keywords : undefined,
 86→      }, locale as 'fr' | 'en' | 'es');
 87→      setReport(result);
 88→      setStep('results');
 89→    } catch (error) {
 90→      console.error(error);
 91→      alert(locale === 'en' ? 'Scan error.' : locale === 'es' ? 'Error de escaneo.' : 'Erreur lors du scan.');
 92→    } finally {
 93→      setIsScanning(false);
 94→    }
 95→  };
 96→
 97→  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
 98→    setExpandedAlert(index);
 99→    setIsGeneratingPlan(true);
100→    setActionPlan(null);
101→    try {
