  1→import React, { useState, useMemo } from 'react';
  2→import { AnalysisResult, Recommendation, GeneratedSolution, User } from '../types';
  3→import { generateSolution } from '../services/generator';
  4→import RecommendationCard from '../components/RecommendationCard';
  5→import GenerationModal from '../components/GenerationModal';
  6→import { Zap, AlertTriangle, Fuel, ArrowRight } from 'lucide-react';
  7→
  8→interface Props {
  9→  data: AnalysisResult;
 10→  user: User | null;
 11→  onDeductCredits: (amount: number) => boolean;
 12→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
 13→  onNavigateToAnalysis: () => void;
 14→  onNavigateToRecharge: () => void;
 15→}
 16→
 17→const ActionPlan: React.FC<Props> = ({ data, user, onDeductCredits, onSaveSolution, onNavigateToAnalysis, onNavigateToRecharge }) => {
 18→  // Generation Modal State
 19→  const [isModalOpen, setIsModalOpen] = useState(false);
 20→  const [isGeneratingSolution, setIsGeneratingSolution] = useState(false);
 21→  const [generatedSolution, setGeneratedSolution] = useState<GeneratedSolution | null>(null);
 22→
 23→  // Fonction utilitaire pour calculer le coût
 24→  const getSolutionCost = (priority: string): number => {
 25→    switch (priority) {
 26→      case 'critical': return 5;
 27→      case 'high': return 4;
 28→      case 'medium': return 3;
 29→      case 'low': return 1;
 30→      default: return 3;
 31→    }
 32→  };
 33→
 34→  // Calcul du coût total restant
 35→  const totalRemainingCost = useMemo(() => {
 36→    if (!data) return 0;
 37→    return data.recommendations.reduce((acc, rec) => {
 38→        // Ne compte pas les coûts des solutions déjà générées
 39→        if (data.generatedSolutions && data.generatedSolutions[rec.id]) return acc;
 40→        return acc + getSolutionCost(rec.priority);
 41→    }, 0);
 42→  }, [data?.recommendations, data?.generatedSolutions]);
 43→
 44→  const handleApplyRecommendation = async (rec: Recommendation) => {
 45→    const cost = getSolutionCost(rec.priority);
 46→
 47→    // La logique de vérification de solde et de redirection est déléguée à onDeductCredits
 48→    const success = onDeductCredits(cost);
 49→    if (!success) {
 50→      return; 
 51→    }
 52→
 53→    setIsModalOpen(true);
 54→    setIsGeneratingSolution(true);
 55→    setGeneratedSolution(null);
 56→
 57→    try {
 58→      const solution = await generateSolution(rec, data.url);
 59→      setGeneratedSolution(solution);
 60→      // PASSAGE DE L'ID D'ANALYSE (data.timestamp) OBLIGATOIRE
 61→      onSaveSolution(data.timestamp, rec.id, solution); 
 62→      
 63→    } catch (error) {
 64→      console.error("Error generating solution", error);
 65→      setGeneratedSolution({
 66→        title: "Erreur de génération",
 67→        explanation: "Le service d'IA est momentanément indisponible.",
 68→        type: 'text',
 69→        content: "Veuillez réessayer dans quelques instants.",
 70→        implementationSteps: ["Réessayez l'opération"]
 71→      });
 72→    } finally {
 73→      setIsGeneratingSolution(false);
 74→    }
 75→  };
 76→
 77→  const handleOpenStoredSolution = (solution: GeneratedSolution) => {
 78→    setGeneratedSolution(solution);
 79→    setIsModalOpen(true);
 80→  };
 81→
 82→  if (!data) {
 83→    return (
 84→        <div className="max-w-6xl mx-auto px-4 py-10 min-h-[80vh] flex flex-col items-center justify-center text-center">
 85→            <div className="w-20 h-20 bg-purple-500/5 rounded-2xl flex items-center justify-center mb-6">
 86→                <Zap size={40} className="text-gray-500" />
 87→            </div>
 88→            <h2 className="text-2xl font-bold text-white mb-2">Aucun plan d'action actif</h2>
 89→            <p className="text-gray-400 max-w-md mb-8">
 90→                Veuillez d'abord lancer une analyse ou sélectionner un projet pour générer un plan d'action AEO.
 91→            </p>
 92→            <button 
 93→                onClick={onNavigateToAnalysis}
 94→                className="px-6 py-3 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-xl hover:from-purple-600 hover:to-violet-700 transition-colors"
 95→            >
 96→                Lancer une analyse
 97→            </button>
 98→        </div>
 99→    );
100→  }
