 26→// Helper to convert AnalysisResult to Project format
 27→const mapAnalysisToProject = (analysis: AnalysisResult, index: number): Project => {
 28→  const hostname = new URL(analysis.url).hostname;
 29→  return {
 30→    id: `proj_${index}_${hostname}`,
 31→    name: hostname,
 32→    domain: analysis.url,
 33→    status: 'active',
 34→    lastRun: analysis.timestamp,
 35→    visibilityScore: analysis.globalScore,
 36→    trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5), // Simulé basé sur le score
 37→    nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
 38→  };
 39→};
