 57→  // Use history to build project list, defaulting to mock if empty for demo
 58→  const projects = useMemo(() => {
 59→    if (history.length > 0) {
 60→      // Deduplicate by URL hostname, keeping the most recent
 61→      const uniqueMap = new Map<string, AnalysisResult>();
 62→      history.forEach(item => {
 63→        try {
 64→            const host = new URL(item.url).hostname;
