583→                    className="w-full py-2.5 bg-purple-500/10 hover:bg-purple-500/20 text-purple-300 border border-purple-500/20 rounded-lg text-sm font-bold transition-all flex items-center justify-center gap-2"
584→                  >
585→                    Voir les solutions <ArrowRight size={14} />
586→                  </button>
587→               </div>
588→            </div>
589→         </div>
590→      </div>
591→
592→      {/* SECTION 2: HISTORIQUE DES ANALYSES */}
593→      <div className="glass-panel rounded-2xl overflow-hidden border border-white/10 mt-8">
594→         <div className="p-6 border-b border-white/10 flex justify-between items-center bg-purple-500/5">
