596→               <Clock size={20} className="text-gray-400" /> Historique des analyses
597→            </h3>
598→            <div className="text-xs text-gray-500">
599→               {projectHistory.length} audits conservés
600→            </div>
601→         </div>
602→         
603→         <div className="overflow-x-auto">
604→            <table className="w-full text-left">
605→               <thead>
606→                  <tr className="bg-[#050208] text-xs text-gray-500 uppercase tracking-wider">
607→                     <th className="px-6 py-4 font-medium">Date</th>
608→                     <th className="px-6 py-4 font-medium">Score Global</th>
609→                     <th className="px-6 py-4 font-medium">Technique</th>
610→                     <th className="px-6 py-4 font-medium">Sémantique</th>
611→                     <th className="px-6 py-4 font-medium">Autorité</th>
612→                     <th className="px-6 py-4 font-medium text-right">Actions</th>
613→                  </tr>
614→               </thead>
615→               <tbody className="divide-y divide-white/5">
616→                  {projectHistory.map((analysis, idx) => (
617→                     <tr key={idx} className={`hover:bg-white/[0.02] transition-colors ${selectedAnalysisState === analysis ? 'bg-primary/5' : ''}`}>
618→                        <td className="px-6 py-4 text-sm text-gray-300">
619→                           {new Date(analysis.timestamp).toLocaleDateString()} <span className="text-gray-600 text-xs ml-1">{new Date(analysis.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
620→                        </td>
621→                        <td className="px-6 py-4">
622→                           <span className={`font-bold ${getScoreColor(analysis.globalScore)}`}>{analysis.globalScore}</span>
623→                        </td>
624→                        <td className="px-6 py-4 text-sm text-gray-400">
625→                           {Math.round(analysis.categories['technical']?.score || 0)}
626→                        </td>
627→                        <td className="px-6 py-4 text-sm text-gray-400">
628→                           {Math.round(analysis.categories['semantic']?.score || 0)}
629→                        </td>
630→                        <td className="px-6 py-4 text-sm text-gray-400">
631→                           {Math.round(analysis.categories['entity']?.score || 0)}
632→                        </td>
633→                        <td className="px-6 py-4 text-right flex justify-end gap-2">
634→                           <button 
635→                              onClick={() => {
636→                                 setSelectedAnalysisState(analysis);
637→                                 setActiveTab('report');
638→                                 window.scrollTo({ top: 0, behavior: 'smooth' });
639→                              }}
640→                              className="text-gray-400 hover:text-white text-xs font-bold px-3 py-1.5 rounded-lg border border-white/10 hover:bg-purple-500/5 transition-colors flex items-center gap-1"
641→                           >
642→                              <ClipboardList size={12} />
643→                              Rapport
644→                           </button>
645→                           <button 
646→                              onClick={() => {
647→                                 setSelectedAnalysisState(analysis);
648→                                 setActiveTab('action-plan');
649→                                 window.scrollTo({ top: 0, behavior: 'smooth' });
650→                              }}
651→                              className="text-primary hover:text-white text-xs font-bold px-3 py-1.5 rounded-lg border border-primary/20 hover:bg-primary/10 transition-colors flex items-center gap-1"
652→                           >
653→                              <Zap size={12} />
654→                              Plan d'Action
655→                           </button>
656→                        </td>
657→                     </tr>
658→                  ))}
659→                  {projectHistory.length === 0 && (
660→                     <tr>
661→                        <td colSpan={6} className="px-6 py-8 text-center text-gray-500 text-sm">
662→                           Aucune analyse enregistrée pour ce projet.
663→                        </td>
664→                     </tr>
665→                  )}
666→               </tbody>
667→            </table>
668→         </div>
669→      </div>
670→
671→    </div>
672→  );
673→};
674→
675→export default Projects;
